<template>  <div class="user-management">    <el-card>      <template #header>        <div class="card-header">          <span>用户管理</span>          <el-button            v-if="authStore.hasPermission('user:create')"            type="primary"            @click="showCreateDialog = true"          >            新增用户          </el-button>        </div>      </template>      <!-- 搜索和筛选 -->      <div class="filter-section">        <el-input          v-model="searchKeyword"          placeholder="搜索用户名或邮箱"          style="width: 300px; margin-right: 10px;"          clearable          @input="handleSearch"        />        <el-select          v-model="statusFilter"          placeholder="选择状态"          style="width: 120px;"          clearable          @change="handleFilter"        >          <el-option label="正常" value="active" />          <el-option label="禁用" value="inactive" />        </el-select>      </div>      <!-- 用户列表 -->      <el-table        :data="filteredUsers"        style="width: 100%"        v-loading="loading"      >        <el-table-column prop="id" label="ID" width="80" />        <el-table-column prop="username" label="用户名" width="120" />        <el-table-column prop="email" label="邮箱" />        <el-table-column prop="status" label="状态" width="100">          <template #default="scope">            <el-tag :type="scope.row.status === 'active' ? 'success' : 'danger'">              {{ scope.row.status === 'active' ? '正常' : '禁用' }}            </el-tag>          </template>        </el-table-column>        <el-table-column prop="createdAt" label="创建时间" width="180">          <template #default="scope">            {{ formatDate(scope.row.createdAt) }}          </template>        </el-table-column>        <el-table-column label="角色" width="200">          <template #default="scope">            <el-tag              v-for="role in scope.row.roles"              :key="role.id"              size="small"              style="margin-right: 5px;"            >              {{ role.name }}            </el-tag>          </template>        </el-table-column>        <el-table-column label="操作" width="200" fixed="right">          <template #default="scope">            <el-button              v-if="authStore.hasPermission('user:update')"              type="primary"              size="small"              @click="editUser(scope.row)"            >              编辑            </el-button>            <el-button              v-if="authStore.hasPermission('user:delete')"              type="danger"              size="small"              @click="deleteUser(scope.row)"              style="margin-left: 10px;"            >              删除            </el-button>          </template>        </el-table-column>      </el-table>      <!-- 分页 -->      <div class="pagination">        <el-pagination          v-model:current-page="currentPage"          v-model:page-size="pageSize"          :page-sizes="[10, 20, 50, 100]"          :total="totalUsers"          layout="total, sizes, prev, pager, next, jumper"          @size-change="handleSizeChange"          @current-change="handleCurrentChange"        />      </div>    </el-card>    <!-- 新增/编辑用户对话框 -->    <el-dialog      v-model="showCreateDialog"      :title="isEditing ? '编辑用户' : '新增用户'"      width="500px"    >      <el-form        ref="userFormRef"        :model="userForm"        :rules="userRules"        label-width="80px"      >        <el-form-item label="用户名" prop="username">          <el-input            v-model="userForm.username"            :disabled="isEditing"            placeholder="请输入用户名"          />        </el-form-item>        <el-form-item          v-if="!isEditing"          label="密码"          prop="password"        >          <el-input            v-model="userForm.password"            type="password"            placeholder="请输入密码"          />        </el-form-item>        <el-form-item label="邮箱" prop="email">          <el-input            v-model="userForm.email"            placeholder="请输入邮箱"          />        </el-form-item>        <el-form-item label="状态" prop="status">          <el-select v-model="userForm.status" placeholder="选择状态">            <el-option label="正常" value="active" />            <el-option label="禁用" value="inactive" />          </el-select>        </el-form-item>        <el-form-item label="角色" prop="roleIds">          <el-select            v-model="userForm.roleIds"            multiple            placeholder="选择角色"            style="width: 100%"          >            <el-option              v-for="role in allRoles"              :key="role.id"              :label="role.name"              :value="role.id"            />          </el-select>        </el-form-item>      </el-form>      <template #footer>        <span class="dialog-footer">          <el-button @click="showCreateDialog = false">取消</el-button>          <el-button            type="primary"            :loading="submitLoading"            @click="handleSubmit"          >            {{ isEditing ? '更新' : '创建' }}          </el-button>        </span>      </template>    </el-dialog>  </div></template><script>import { ref, reactive, onMounted, computed } from 'vue'import { useAuthStore } from '../stores/auth'import axios from 'axios'import { ElMessage, ElMessageBox } from 'element-plus'export default {  name: 'UserManagementView',  setup() {    const authStore = useAuthStore()    const users = ref([])    const allRoles = ref([])    const loading = ref(false)    const submitLoading = ref(false)    const showCreateDialog = ref(false)    const isEditing = ref(false)    const searchKeyword = ref('')    const statusFilter = ref('')    const currentPage = ref(1)    const pageSize = ref(10)    const totalUsers = ref(0)    const userFormRef = ref()    const userForm = reactive({      id: null,      username: '',      password: '',      email: '',      status: 'active',      roleIds: []    })    const userRules = {      username: [        { required: true, message: '请输入用户名', trigger: 'blur' },        { min: 3, max: 20, message: '用户名长度在 3 到 20 个字符', trigger: 'blur' }      ],      password: [        { required: !isEditing.value, message: '请输入密码', trigger: 'blur' },        { min: 6, message: '密码长度不能少于 6 个字符', trigger: 'blur' }      ],      email: [        { type: 'email', message: '请输入正确的邮箱格式', trigger: 'blur' }      ],      status: [        { required: true, message: '请选择状态', trigger: 'change' }      ]    }    // 计算过滤后的用户列表    const filteredUsers = computed(() => {      let filtered = users.value      // 搜索关键词      if (searchKeyword.value) {        filtered = filtered.filter(user =>          user.username.toLowerCase().includes(searchKeyword.value.toLowerCase()) ||          (user.email && user.email.toLowerCase().includes(searchKeyword.value.toLowerCase()))        )      }      // 状态筛选      if (statusFilter.value) {        filtered = filtered.filter(user => user.status === statusFilter.value)      }      // 分页      const start = (currentPage.value - 1) * pageSize.value      const end = start + pageSize.value      // totalUsers.value = filtered.length      return filtered.slice(start, end)    })    const fetchUsers = async () => {      if (!authStore.hasPermission('user:list')) return      loading.value = true      try {        const response = await axios.get('http://localhost:3000/api/users', {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          users.value = response.data.data        }      } catch (error) {        console.error('Fetch users error:', error)        ElMessage.error('获取用户列表失败')      } finally {        loading.value = false      }    }    const fetchRoles = async () => {      if (!authStore.hasPermission('role:list')) return      try {        const response = await axios.get('http://localhost:3000/api/roles', {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          allRoles.value = response.data.data        }      } catch (error) {        console.error('Fetch roles error:', error)      }    }    const handleSearch = () => {      currentPage.value = 1    }    const handleFilter = () => {      currentPage.value = 1    }    const handleSizeChange = (val) => {      pageSize.value = val      currentPage.value = 1    }    const handleCurrentChange = (val) => {      currentPage.value = val    }    const resetForm = () => {      userForm.id = null      userForm.username = ''      userForm.password = ''      userForm.email = ''      userForm.status = 'active'      userForm.roleIds = []    }    const editUser = (user) => {      isEditing.value = true      userForm.id = user.id      userForm.username = user.username      userForm.email = user.email || ''      userForm.status = user.status      userForm.roleIds = user.roles ? user.roles.map(r => r.id) : []      showCreateDialog.value = true    }    const deleteUser = async (user) => {      try {        await ElMessageBox.confirm(          `确定要删除用户 "${user.username}" 吗？此操作不可恢复。`,          '确认删除',          {            confirmButtonText: '确定',            cancelButtonText: '取消',            type: 'warning',          }        )        const response = await axios.delete(`http://localhost:3000/api/users/${user.id}`, {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          ElMessage.success('删除成功')          fetchUsers()        }      } catch (error) {        if (error !== 'cancel') {          console.error('Delete user error:', error)          ElMessage.error('删除失败')        }      }    }    const handleSubmit = async () => {      try {        await userFormRef.value.validate()        submitLoading.value = true        const formData = {          username: userForm.username,          email: userForm.email || undefined,          status: userForm.status        }        if (!isEditing.value) {          formData.password = userForm.password        }        let response        if (isEditing.value) {          if (!authStore.hasPermission('user:update')) {            ElMessage.error('没有编辑权限')            return          }          response = await axios.put(`http://localhost:3000/api/users/${userForm.id}`, formData, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        } else {          if (!authStore.hasPermission('user:create')) {            ElMessage.error('没有创建权限')            return          }          response = await axios.post('http://localhost:3000/api/users', formData, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        }        if (response.data.success) {          ElMessage.success(isEditing.value ? '更新成功' : '创建成功')          showCreateDialog.value = false          resetForm()          fetchUsers()        }      } catch (error) {        console.error('Submit user error:', error)        ElMessage.error(error.response?.data?.message || '操作失败')      } finally {        submitLoading.value = false      }    }    const formatDate = (dateString) => {      return new Date(dateString).toLocaleString('zh-CN')    }    onMounted(() => {      fetchUsers()      fetchRoles()    })    return {      authStore,      users,      allRoles,      loading,      submitLoading,      showCreateDialog,      isEditing,      searchKeyword,      statusFilter,      currentPage,      pageSize,      totalUsers,      filteredUsers,      userFormRef,      userForm,      userRules,      handleSearch,      handleFilter,      handleSizeChange,      handleCurrentChange,      editUser,      deleteUser,      handleSubmit,      formatDate    }  }}</script><style scoped>.user-management {  padding: 20px;}.card-header {  display: flex;  justify-content: space-between;  align-items: center;}.filter-section {  margin-bottom: 20px;  display: flex;  align-items: center;}.pagination {  margin-top: 20px;  text-align: right;}.dialog-footer {  text-align: right;}</style>